+
+/* ====== LOGIN ESTILO POCKET ====== */
+.login-pocketIN {
+  display: flex;
+  height: 100vh;
+  background-color: #fff;
+}
+
+/* Lado izquierdo con imagen */
+.login-visual {
+  flex: 1;
+  background-color: #fafafa;
+  display: flex;
+  justify-content: center;
+  align-items: center;
+  padding: 2rem;
+}
+
+.login-visual img {
+  width: 90%;
+  max-width: 600px;
+  border-radius: 10px;
+  box-shadow: 0 4px 30px rgba(0, 0, 0, 0.1);
+}
+
+/* Lado derecho con formulario */
+.login-form-section {
+  flex: 1;
+  display: flex;
+  justify-content: center;
+  align-items: center;
+  padding: 2rem;
+}
+
+.login-box {
+  width: 90%;
+  max-width: 400px;
+  text-align: center;
+}
+
+.login-box h1 {
+  color: var(--accent-color, #f39135);
+  font-size: 1.8rem;
+  margin-bottom: 3rem;
+}
+
+.login-box p {
+  color: #666;
+  margin-bottom: 1.5rem;
+}
+
+.form-login .form-group {
+  text-align: left;
+  margin-bottom: 1rem;
+}
+
+.form-login label {
+  display: block;
+  font-size: 0.9rem;
+  color: #444;
+  margin-bottom: 0.3rem;
+}
+
+.form-login input {
+  width: 88%;
+  padding: 0.8rem;
+  border: 1px solid #ccc;
+  border-radius: 8px;
+  font-size: 1rem;
+  outline: none;
+  transition: 0.3s;
+}
+
+.form-login input:focus {
+  border-color: var(--accent-color, #f37335);
+  box-shadow: 0 0 5px rgba(243,115,53,0.3);
+}
+
+.btn-login-pocket {
+  background-color: var(--accent-color, #070658);
+  color: white;
+  border: none;
+  border-radius: 8px;
+  width: 80%;
+  padding: 0.9rem;
+  font-size: 1rem;
+  cursor: pointer;
+  transition: background 0.3s ease;
+}
+
+.btn-login-pocket:hover {
+  background-color: #303030;
+}
+
+.forgot {
+  display: block;
+  margin-top: 0.8rem;
+  color: #1d1d1d;
+  font-size: 1rem;
+  text-decoration: none;
+}
+
+.divider {
+  margin: 1.5rem 0;
+  position: relative;
+  text-align: center;
+  color: #aaa;
+}
+
+.divider::before, .divider::after {
+  content: "";
+  position: absolute;
+  top: 50%;
+  width: 40%;
+  height: 1px;
+  background-color: #ddd;
+}
+
+.divider::before { left: 0; }
+.divider::after { right: 0; }
+
+.social-login {
+  display: flex;
+  flex-direction: column;
+  gap: 0.7rem;
+}
+
+.social-btn {
+  border: 1px solid #ddd;
+  border-radius: 8px;
+  padding: 0.8rem;
+  background-color: #fff;
+  cursor: pointer;
+  transition: background 0.3s;
+}
+
+.social-btn:hover {
+  background-color: #f8f8f8;
+}
+
+.google { color: #252525; }
